# =============================================================================
# Audit Codes
# =============================================================================
class AuditCode(Enum):

    # --------------------------------------------------
    # Components
    # --------------------------------------------------

    ASM001 = "ASM-001"     # Missing Component ID
    ASM002 = "ASM-002"     # Missing Component Name
    ASM003 = "ASM-003"     # Component not found in Model Database
    ASM004 = "ASM-004"     # Duplicate Component ID
    ASM005 = "ASM-005"     # Duplicate Component Name

    # --------------------------------------------------
    # Hierarchy
    # --------------------------------------------------

    ASM020 = "ASM-020"     # Invalid Parent Name
    ASM021 = "ASM-021"     # Component cannot be parent of itself
    ASM022 = "ASM-022"     # Parent Loop
    ASM023 = "ASM-023"     # Parent Disabled

    ASM024 = "ASM-024"     # No Root Component
    ASM025 = "ASM-025"     # Multiple Root Components
    ASM026 = "ASM-026"     # Component not connected to Root

    # --------------------------------------------------
    # Objects
    # --------------------------------------------------

    ASM040 = "ASM-040"     # Object Component Reference
    ASM041 = "ASM-041"     # Missing Object Name
    ASM042 = "ASM-042"     # Unsupported Object Type
    ASM043 = "ASM-043"     # Component without Objects
    ASM044 = "ASM-044"     # Invalid Motor Mode
    ASM045 = "ASM-045"     # Invalid Joint Type
    ASM046 = "ASM-046"     # Invalid Reference Frame

    # --------------------------------------------------
    # Model Database
    # --------------------------------------------------

    ASM060 = "ASM-060"     # Bounding Box Missing
    ASM061 = "ASM-061"     # Frame Missing
    ASM062 = "ASM-062"     # Models Section Missing"

# =============================================================================
# Audit Message
# =============================================================================
class AuditMessage:
    """
    Represents a validation or audit message generated during the GSPL pipeline.
    """

    def __init__(
        self,
        code: str,
        severity: str,
        message: str,
        component: str = "",
        object_name: str = ""
    ):

        self.code = code
        self.severity = severity.upper()
        self.component = component
        self.object_name = object_name
        self.message = message

    # ------------------------------------------------------------------
    # String Representation
    # ------------------------------------------------------------------
    def __str__(self):

        text = f"[{self.code}] {self.severity}"
        if self.component:
            text += f" | Component: {self.component}"

        if self.object_name:
            text += f" | Object: {self.object_name}"

        text += f" | {self.message}"

        return text

    # ------------------------------------------------------------------
    # Dictionary Representation
    # ------------------------------------------------------------------
    def to_dict(self):

        return {

            "code": self.code,

            "severity": self.severity,

            "component": self.component,

            "object": self.object_name,

            "message": self.message

        }

